ary: "Rule moves LOAN_APPLICATION from UNKNOWN or IDLE into ELIGIBILITY_GATE.", session: ["state=ELIGIBILITY_GATE -> COMPLETED"], tables: ["ce_rule (R)", "ce_audit (W)"] }, r2: { title: "Post-MCP transition", stage: "POST_AGENT_MCP", summary: "After planner ANSWER, POST_AGENT_MCP rule checks context.mcp.finalAnswer and moves state from ELIGIBILITY_GATE to COMPLETED.", session: ["state=COMPLETED"], tables: ["ce_rule (R)", "ce_audit (W)"] }, m1: { title: "MCP plan #1", stage: "MCP_PLAN_LLM_OUTPUT", summary: "Planner decides first check must be credit rating.", session: ["CALL_TOOL loan.credit.rating.check"], tables: ["ce_mcp_tool (R)", "ce_mcp_planner (R)", "ce_audit (W)"] }, t1: { title: "loan.credit.rating.check", stage: "MCP_TOOL_RESULT", summary: "Mapped rating response appended to context.mcp.observations.", session: ["observation[0]=rating"], tables: ["ce_audit (W)"] }, m2: { title: "MCP plan #2", stage: "MCP_PLAN_LLM_OUTPUT", summary: "If rating > 750 planner proceeds to fraud check.", session: ["CALL_TOOL loan.credit.fraud.check"], tables: ["ce_mcp_planner (R)", "ce_audit (W)"] }, t2: { title: "loan.credit.fraud.check", stage: "MCP_TOOL_RESULT", summary: "Fraud result stored as second observation.", session: ["observation[1]=fraud"], tables: ["ce_audit (W)"] }, m3: { title: "MCP plan #3", stage: "MCP_PLAN_LLM_OUTPUT", summary: "If fraud false planner asks debt/credit summary.", session: ["CALL_TOOL loan.debt.credit.summary"], tables: ["ce_mcp_planner (R)", "ce_audit (W)"] }, t3: { title: "loan.debt.credit.summary", stage: "MCP_TOOL_RESULT", summary: "Debt metrics (dti, availableCredit) added to observations.", session: ["observation[2]=debt"], tables: ["ce_audit (W)"] }, m4: { title: "MCP plan #4", stage: "MCP_PLAN_LLM_OUTPUT", summary: "If affordability passes, planner triggers submit API.", session: ["CALL_TOOL loan.application.submit"], tables: ["ce_mcp_planner (R)", "ce_audit (W)"] }, t4: { title: "loan.application.submit", stage: "MCP_TOOL_RESULT", summar