nvengine-demo/.../LoanCreditRatingToolHandler.java - convengine-demo/.../LoanFraudCheckToolHandler.java - convengine-demo/.../LoanDebtSummaryToolHandler.java - convengine-demo/.../LoanApplicationSubmitToolHandler.java ## Seed packs - Postgres: convengine-demo/src/main/resources/sql/example2_seed.sql - SQLite: convengine-demo/src/main/resources/sql/example2_sqlite_seed.sql These seed files include all required DML: - ce_intent - ce_intent_classifier - ce_output_schema - ce_prompt_template - ce_response - ce_rule - ce_mcp_tool (with intent_code + state_code ) - ce_mcp_planner scoped prompt rows (default + LOAN_APPLICATION/ELIGIBILITY_GATE) ## Required rule/response rows for this flow Use these key rows so classifier + MCP + response resolution line up correctly: sql -- 1) Bootstrap state after classifier picks LOAN_APPLICATION INSERT INTO ce_rule (intent_code, state_code, rule_type, match_pattern, action, action_value, phase, priority, enabled, description) VALUES ('LOAN_APPLICATION', 'UNKNOWN', 'REGEX', '.*', 'SET_STATE', 'ELIGIBILITY_GATE', 'POST_AGENT_INTENT', 20, true, 'Move LOAN_APPLICATION from UNKNOWN into ELIGIBILITY_GATE.'); -- 2) After MCP planner returns ANSWER, close state for final response mapping INSERT INTO ce_rule (intent_code, state_code, rule_type, match_pattern, action, action_value, phase, priority, enabled, description) VALUES ('LOAN_APPLICATION', 'ELIGIBILITY_GATE', 'JSON_PATH', '$[?(@.context.mcp.finalAnswer != null && @.context.mcp.finalAnswer != '''')]', 'SET_STATE', 'COMPLETED', 'POST_AGENT_MCP', 30, true, 'Move loan flow to COMPLETED only when context.mcp.finalAnswer exists.'); -- 3) Final response row should target COMPLETED and derive from MCP context INSERT INTO ce_response (intent_code, state_code, output_format, response_type, derivation_hint, priority, enabled, description) VALUES ('LOAN_APPLICATION', 'COMPLETED', 'TEXT', 'DERIVED', 'Use context.mcp.finalAnswer as primary summary. Validate with context.mcp.observations (rating/fraud/debt/submit). Do not invent values.', 20, true, 'Loan decision derived from MCP outputs.'); -- 4) Prompt template should explicitly read context.mcp.* INSERT INTO ce_prompt_template (intent_code, state_code, response_type, system_prompt, user_prompt, interaction_mode, interaction_contract, enabled) VALUES ('LOAN_APPLICATION', 'COMPLETED', 'TEXT', 'You are a precise loan workflow summarizer. Use only MCP evidence from context JSON.', 'Context JSON:
